INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Wind (aeolian) erosion or deposition', 'erosionCategoryValueCode-A', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-A', 'Erosion caused by wind', 'A') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Wind deposition', 'erosionCategoryValueCode-AD', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-AD', 'Soil deposition caused by wind', 'AD') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Wind erosion and deposition', 'erosionCategoryValueCode-AM', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-AM', 'Erosion and deposition caused by wind', 'AM') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Shifting sands', 'erosionCategoryValueCode-AS', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-AS', 'Erosion caused by shifting of sands', 'AS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Salt deposition', 'erosionCategoryValueCode-AZ', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-AZ', 'Erosion caused by salt deposition', 'AZ') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Mass movement', 'erosionCategoryValueCode-M', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-M', 'Mass movements are defined as processes of erosion, transport and accumulation of material that occur on both gentle and steep slopes mainly owing to gravitational forces.', 'N') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('No evidence of erosion', 'erosionCategoryValueCode-N', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-N', 'Refers to a condition in which the soil shows no visible signs of erosion, indicating that the surface is intact and not undergoing significant degradation due to physical forces like water, wind, or human activity. This category is often used in soil conservation and land management to evaluate the stability of soil. It suggests that soil properties are being maintained, and there is no noticeable loss of topsoil or alteration in the soil structure that would be indicative of erosion processes such as rill, sheet, or gully erosion. In agricultural and ecological contexts, the absence of erosion is a positive indicator that the land is being properly managed, with adequate vegetation cover or protective measures in place to prevent soil degradation​. Source: Soil Erosion from Intro to Environmental Science', 'N') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Not known', 'erosionCategoryValueCode-NK', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-NK', 'Unknown causes of Soil erosion', 'N') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Water erosion or deposition', 'erosionCategoryValueCode-W', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-W', 'Erosion and decposition caused by flowing surface water', 'W') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Water and wind erosion', 'erosionCategoryValueCode-WA', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-WA', 'Erosion and deposition caused by wind', 'WA') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Deposition by water', 'erosionCategoryValueCode-WD', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-WD', 'Soil deposition caused by water', 'WD') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Gully erosion', 'erosionCategoryValueCode-WG', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-WG', 'Erosion caused by flowing surface water', 'WG') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Rill erosion', 'erosionCategoryValueCode-WR', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-WR', 'Rill erosion is the type of erosion that occurs as water flows over a hillslope and cuts shallow, curvy channels into the top soil.', 'WR') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Sheet erosion', 'erosionCategoryValueCode-WS', 'http://w3id.org/glosis/model/codelists/erosionCategoryValueCode-WS', 'Uniform erosion of soil in the form of thin layers or sheets.', 'WS') ON CONFLICT DO NOTHING;
