INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Routine profile description - no sampling', 'profileDescriptionStatusValueCode-2.1', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-2.1', 'If soil description is done without sampling.', '2.1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Soil augering description - no sampling', 'profileDescriptionStatusValueCode-4.1', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-4.1', 'If soil description is done without sampling.', '4.1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Reference profile description - no sampling', 'profileDescriptionStatusValueCode-1.1', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-1.1', 'If soil description is done without sampling.', '1.1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Incomplete description - no sampling', 'profileDescriptionStatusValueCode-3.1', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-3.1', 'If soil description is done without sampling.', '3.1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Reference profile description', 'profileDescriptionStatusValueCode-1', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-1', 'No essential elements or details are missing from the description, sampling or analysis. The accuracy and reliability of the description and analytical results permit the full characterization of all soil horizons to a depth of 125 cm, or more if required for classification, or down to a C or R horizon or layer, which may be shallower.', '1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Soil augering description', 'profileDescriptionStatusValueCode-4', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-4', 'Soil augerings do no permit a comprehensive soil profile description. Augerings are made for routine soil observation and identification in soil mapping, and for that purpose normally provide a satisfactory indication of the soil characteristics. Soil samples may be collected from augerings.', '4') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Routine profile description', 'profileDescriptionStatusValueCode-2', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-2', 'No essential elements are missing from the description, sampling or analysis. The number of samples collected is sufficient to characterize all major soil horizons, but may not allow precise definition of all subhorizons, especially in the deeper soil. The profile depth is 80 cm or more, or down to a C or R horizon or layer, which may be shallower. Additional augering and sampling may be required for lower level classification.', '2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Other descriptions', 'profileDescriptionStatusValueCode-5', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-5', 'Essential elements are missing from the description, preventing a satisfactory soil characterization and classification.', '5') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Incomplete description', 'profileDescriptionStatusValueCode-3', 'http://w3id.org/glosis/model/codelists/profileDescriptionStatusValueCode-3', 'Certain relevant elements are missing from the description, an insufficient number of samples was collected, or the reliability of the analytical data does not permit a complete characterization of the soil. However, the description is useful for specific purposes and provides a satisfactory indication of the nature of the soil at high levels of soil taxonomic classification.', '3') ON CONFLICT DO NOTHING;
