INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Many pores, moist materials drop easily out of the auger.', 'bulkDensityMineralValueCode-BD1', 'http://w3id.org/glosis/model/codelists/bulkDensityMineralValueCode-BD1', 'materials with vesicular pores, mineral soils with andic properties. Sample disintegrates at the instant of sampling, many pores visible onthe pit wall. Sample disintegrates at the instant of sampling, many pores visible on the pit wall. Loamy soils with high clay content, clayey soils When dropped, sample disintegrates into numerous fragments, further disintegration of subfragments after application of weak pressure.', 'BD1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Sample disintegrates into numerous fragments after application of weak pressure.', 'bulkDensityMineralValueCode-BD2', 'http://w3id.org/glosis/model/codelists/bulkDensityMineralValueCode-BD2', 'Loamy soils with high clay content, clayey soils. When dropped, sample disintegrates into few fragments, further disintegration of subfragments after application of mild pressure.', 'BD2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Knife can be pushed into the moist soil with weak pressure, sample disintegrates into few fragments, which may be further divided.', 'bulkDensityMineralValueCode-BD3', 'http://w3id.org/glosis/model/codelists/bulkDensityMineralValueCode-BD3', 'Loamy soils with high clay content, clayey soils. Sample remains mostly intact when dropped, further disintegration possible after application of large pressure.', 'BD3') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Knife penetrates only 1–2 cm into the moist soil, some effort required, sample disintegrates into few fragments, which cannot be subdivided further.', 'bulkDensityMineralValueCode-BD4', 'http://w3id.org/glosis/model/codelists/bulkDensityMineralValueCode-BD4', 'Loamy soils with high clay content, clayey soils. Sample remains intact when dropped, no further disintegration after application of very large pressure.', 'BD4') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very large pressure necessary to force knife into the soil, no further disintegration of sample.', 'bulkDensityMineralValueCode-BD5', 'http://w3id.org/glosis/model/codelists/bulkDensityMineralValueCode-BD5', 'Loamy soils with high clay content, clayey soils. Sample remains intact when dropped, no further disintegration after application of very large pressure.', 'BD5') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very low', 'bulkDensityPeatValueCode-BD1', 'http://w3id.org/glosis/model/codelists/bulkDensityPeatValueCode-BD1', 'Very low (fibric) class of decomposition: < 0.04g cm-3', 'BD1') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Low', 'bulkDensityPeatValueCode-BD2', 'http://w3id.org/glosis/model/codelists/bulkDensityPeatValueCode-BD2', 'Low (fibric) class of decomposition: 0.04–0.07g cm-3', 'BD2') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Moderate low', 'bulkDensityPeatValueCode-BD3', 'http://w3id.org/glosis/model/codelists/bulkDensityPeatValueCode-BD3', 'Moderate(fibric) class of decomposition: 0.07–0.11g cm-3', 'BD3') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Moderate high', 'bulkDensityPeatValueCode-BD4', 'http://w3id.org/glosis/model/codelists/bulkDensityPeatValueCode-BD4', 'Moderate(fibric) class of decomposition: 0.11–0.17g cm-3', 'BD4') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Strong (hemic)', 'bulkDensityPeatValueCode-BD5', 'http://w3id.org/glosis/model/codelists/bulkDensityPeatValueCode-BD5', 'Strong (hemic) class of decomposition: > 0.17g cm-3', 'BD5') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Extremely calcareous', 'carbonatesContentValueCode-EX', 'http://w3id.org/glosis/model/codelists/carbonatesContentValueCode-EX', 'Extremely strong reaction forming thick foam forms quickly: ≈ > 25', 'EX') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Moderately calcareous', 'carbonatesContentValueCode-MO', 'http://w3id.org/glosis/model/codelists/carbonatesContentValueCode-MO', 'Visible effervescence: ≈ 2–10', 'MO') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Non-calcareous', 'carbonatesContentValueCode-N', 'http://w3id.org/glosis/model/codelists/carbonatesContentValueCode-N', 'No detectable visible or audible effervescence.', 'N') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Slightly calcareous', 'carbonatesContentValueCode-SL', 'http://w3id.org/glosis/model/codelists/carbonatesContentValueCode-SL', 'Audible effervescence but not visible: ≈ 0–2', 'SL') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Strongly calcareous', 'carbonatesContentValueCode-ST', 'http://w3id.org/glosis/model/codelists/carbonatesContentValueCode-ST', 'Strong visible effervescence. Bubbles form a low foam: ≈ 10–25', 'ST') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('disperse powdery lime', 'carbonatesFormsValueCode-D', 'http://w3id.org/glosis/model/codelists/carbonatesFormsValueCode-D', 'Secondary carbonates in soil in the form of disperse powdery lime', 'D') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('hard concretions', 'carbonatesFormsValueCode-HC', 'http://w3id.org/glosis/model/codelists/carbonatesFormsValueCode-HC', 'Secondary carbonates in soil in the form of hard concretions', 'HC') ON CONFLICT DO NOTHING;
