INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('hard cemented layer or layers of carbonates (less than 10 cm thick)', 'carbonatesFormsValueCode-HL', 'http://w3id.org/glosis/model/codelists/carbonatesFormsValueCode-HL', 'Secondary carbonates in soil in the form of hard cemented layer or layers of carbonates', 'HL') ON CONFLICT DO NOTHING;
