INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Broken', 'cementationContinuityValueCode-B', 'http://w3id.org/glosis/model/codelists/cementationContinuityValueCode-B', 'The layer is less than 50 percent cemented or compacted, and shows a rather irregular appearance.', 'B') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Continuous', 'cementationContinuityValueCode-C', 'http://w3id.org/glosis/model/codelists/cementationContinuityValueCode-C', 'The layer is more than 90 percent cemented or compacted, and is only interrupted in places by cracks or fissures.', 'C') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Discontinuous', 'cementationContinuityValueCode-D', 'http://w3id.org/glosis/model/codelists/cementationContinuityValueCode-D', 'The layer is 50–90 percent cemented or compacted, and in general shows a regular appearance.', 'D') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Cemented', 'cementationDegreeValueCode-C', 'http://w3id.org/glosis/model/codelists/cementationDegreeValueCode-C', 'Cemented mass cannot be broken in the hands and is continuous (more than 90 percent of soil mass).', 'C') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Indurated', 'cementationDegreeValueCode-I', 'http://w3id.org/glosis/model/codelists/cementationDegreeValueCode-I', 'Cemented mass cannot be broken by body weight (75-kg standard soil scientist) (more than 90 percent of soil mass).', 'I') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Moderately cemented', 'cementationDegreeValueCode-M', 'http://w3id.org/glosis/model/codelists/cementationDegreeValueCode-M', 'Cemented mass cannot be broken in the hands but is discontinuous (less than 90 percent of soil mass).', 'M') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Non-cemented and non-compacted', 'cementationDegreeValueCode-N', 'http://w3id.org/glosis/model/codelists/cementationDegreeValueCode-N', 'Neither cementation nor compaction observed (slakes in water).', 'N') ON CONFLICT DO NOTHING;
