INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Abundant', 'coatingAbundanceValueCode-A', 'http://w3id.org/glosis/model/codelists/coatingAbundanceValueCode-A', '40–80% of coating abundance', 'A') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Common', 'coatingAbundanceValueCode-C', 'http://w3id.org/glosis/model/codelists/coatingAbundanceValueCode-C', '5–15% of coating abundance', 'C') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Dominant', 'coatingAbundanceValueCode-D', 'http://w3id.org/glosis/model/codelists/coatingAbundanceValueCode-D', '> 80% of coating abundance', 'D') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Few', 'coatingAbundanceValueCode-F', 'http://w3id.org/glosis/model/codelists/coatingAbundanceValueCode-F', '2–5% of coating abundance', 'F') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Many', 'coatingAbundanceValueCode-M', 'http://w3id.org/glosis/model/codelists/coatingAbundanceValueCode-M', '15–40% of coating abundance', 'M') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('None', 'coatingAbundanceValueCode-N', 'http://w3id.org/glosis/model/codelists/coatingAbundanceValueCode-N', '0% of coating abundance', 'N') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very few', 'coatingAbundanceValueCode-V', 'http://w3id.org/glosis/model/codelists/coatingAbundanceValueCode-V', '0–2 % of coating abundance', 'V') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Distinct', 'coatingContrastValueCode-D', 'http://w3id.org/glosis/model/codelists/coatingContrastValueCode-D', 'Surface of coating is distinctly smoother or different in colour from the adjacent surface. Fine sand grains are enveloped in the coating but their outlines are still visible. Lamellae are 2–5 mm thick.', 'D') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Faint', 'coatingContrastValueCode-F', 'http://w3id.org/glosis/model/codelists/coatingContrastValueCode-F', 'Surface of coating shows only little contrast in colour, smoothness or any other property to the adjacent surface. Fine sand grains are readily apparent in the cutan. Lamellae are less than 2 mm thick.', 'F') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Prominent', 'coatingContrastValueCode-P', 'http://w3id.org/glosis/model/codelists/coatingContrastValueCode-P', 'Surface of coatings contrasts strongly in smoothness or colour with the adjacent surfaces. Outlines of fine sand grains are not visible. Lamellae are more than 5 mm thick.', 'P') ON CONFLICT DO NOTHING;
