INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Both hard and soft.', 'mineralConcHardnessValueCode-B', 'http://w3id.org/glosis/model/codelists/mineralConcHardnessValueCode-B', 'Both hard and soft.', 'B') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Hard', 'mineralConcHardnessValueCode-H', 'http://w3id.org/glosis/model/codelists/mineralConcHardnessValueCode-H', 'Cannot be broken in the fingers.', 'H') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Soft', 'mineralConcHardnessValueCode-S', 'http://w3id.org/glosis/model/codelists/mineralConcHardnessValueCode-S', 'Can be broken between forefinger and thumb nail', 'S') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Concretion', 'mineralConcKindValueCode-C', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-C', 'A discrete body with a concentric internal structure, generally cemented.', 'C') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Crack infillings', 'mineralConcKindValueCode-IC', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-IC', 'Crack infillings refer to the materials that accumulate within cracks or fissures in the soil, typically formed due to drying or other physical stresses on the soil structure. These materials can include clays, silt, sand, or mineral deposits that enter cracks over time, often through the action of water or wind. Crack infillings can influence the soil''s physical properties, such as its permeability and structure, as they may either facilitate or impede the movement of water and air through the soil. Additionally, crack infillings can impact soil fertility, as they may contain higher concentrations of certain nutrients or minerals that accumulate in these voids. Source: Soil Science Society of America.', 'IC') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Pore infillings', 'mineralConcKindValueCode-IP', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-IP', 'Including pseudomycelium of carbonates or opal.', 'IP') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Nodule', 'mineralConcKindValueCode-N', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-N', 'Discrete body without an internal organization.', 'N') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Other', 'mineralConcKindValueCode-O', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-O', 'The term Other in the context of soil mineral concentrations generally refers to any minerals or materials found in the soil that do not fall under commonly categorized types such as clay, silt, or sand. This could include uncommon minerals, organic matter, or anthropogenic substances that are present in the soil but don''t fit into the standard classifications of soil texture or composition. These other substances may have a significant effect on soil properties, influencing aspects like nutrient availability, soil pH, and the ability to retain water. In many cases, Other minerals are identified through advanced soil testing and chemical analysis. Source: Soil Science Society of America.', 'O') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Residual rock fragment', 'mineralConcKindValueCode-R', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-R', 'Discrete impregnated body still showing rock structure.', 'R') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Soft segregation (or soft accumulation)', 'mineralConcKindValueCode-S', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-S', 'Differs from the surrounding soil mass in colour and composition but is not easily separated as a discrete body.', 'S') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Soft concretion', 'mineralConcKindValueCode-SC', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-SC', 'Soft concretion', 'SC') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Crystal', 'mineralConcKindValueCode-T', 'http://w3id.org/glosis/model/codelists/mineralConcKindValueCode-T', 'Crystals in soil refer to solid, naturally occurring minerals that have a regular and repeating internal structure, which can often be seen under a microscope or with the naked eye. These crystal formations typically occur when minerals precipitate from water or melt and re-crystallize under certain environmental conditions, such as changes in temperature or pressure. Common crystal minerals in soil include quartz, gypsum, calcite, and halite. The presence of crystals in soil can significantly affect its properties, including drainage, fertility, and nutrient availability. For example, gypsum crystals can improve soil structure, while the presence of salt crystals can lead to soil salinity problems. Source: Brady & Weil (2017), The Nature and Properties of Soils.', 'T') ON CONFLICT DO NOTHING;
