INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Distinct', 'contrastValueCode-D', 'http://w3id.org/glosis/model/codelists/contrastValueCode-D', 'Although not striking, the mottles are readily seen. The hue, chroma and value of the matrix are easily distinguished from those of the mottles. They may vary by as much as 2.5 units of hue or several units in chroma or value.', 'D') ON CONFLICT DO NOTHING;
