INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Prominent', 'contrastValueCode-P', 'http://w3id.org/glosis/model/codelists/contrastValueCode-P', 'The mottles are conspicuous and mottling is one of the outstanding features of the horizon. Hue, chroma and value alone or in combination are at least several units apart.', 'P') ON CONFLICT DO NOTHING;
