INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Non-plastic', 'plasticityValueCode-NPL', 'http://w3id.org/glosis/model/codelists/plasticityValueCode-NPL', 'No wire is formable.', 'NPL') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Plastic', 'plasticityValueCode-PL', 'http://w3id.org/glosis/model/codelists/plasticityValueCode-PL', 'Wire formable but breaks if bent into a ring; slight to moderate force required for deformation of the soil mass.', 'PL') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('plastic to very plastic', 'plasticityValueCode-PVP', 'http://w3id.org/glosis/model/codelists/plasticityValueCode-PVP', 'Additioanl plasticity code with combination of  PL and VPL', 'PVP') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Slightly plastic', 'plasticityValueCode-SPL', 'http://w3id.org/glosis/model/codelists/plasticityValueCode-SPL', 'Wire formable but breaks immediately if bent into a ring; soil mass deformed by very slight force.', 'SPL') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('slightly plastic to plastic', 'plasticityValueCode-SPP', 'http://w3id.org/glosis/model/codelists/plasticityValueCode-SPP', 'Additioanl plasticity code with combination of  SPL and PL', 'SPP') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very plastic', 'plasticityValueCode-VPL', 'http://w3id.org/glosis/model/codelists/plasticityValueCode-VPL', 'Wire formable and can be bent into a ring; moderately strong to very strong force required for deformation of the soil mass.', 'VPL') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Common', 'poresAbundanceValueCode-C', 'http://w3id.org/glosis/model/codelists/poresAbundanceValueCode-C', '< 2 mm (number)50–200 ;> 2 mm (number)5–20', 'C') ON CONFLICT DO NOTHING;
