INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('None', 'poresAbundanceValueCode-N', 'http://w3id.org/glosis/model/codelists/poresAbundanceValueCode-N', '< 2 mm (number)0;> 2 mm (number)0', 'N') ON CONFLICT DO NOTHING;
