INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('High', 'porosityClassValueCode-4', 'http://w3id.org/glosis/model/codelists/porosityClassValueCode-4', 'High porosity of 15–40%', '4') ON CONFLICT DO NOTHING;
