INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Common', 'rootsAbundanceValueCode-C', 'http://w3id.org/glosis/model/codelists/rootsAbundanceValueCode-C', '< 2 mm (number)50–200 ;> 2 mm (number)5–20', 'C') ON CONFLICT DO NOTHING;
