INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Extremely salty', 'saltContentValueCode-EX', 'http://w3id.org/glosis/model/codelists/saltContentValueCode-EX', 'Extremely salty soil with salt content > 15 dS m-1', 'EX') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Moderately salty', 'saltContentValueCode-MO', 'http://w3id.org/glosis/model/codelists/saltContentValueCode-MO', 'Extremely salty soil with salt content 2–4 dS m-1', 'MO') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('(nearly)Not salty', 'saltContentValueCode-N', 'http://w3id.org/glosis/model/codelists/saltContentValueCode-N', 'Nearly not salty soild with salt content less than  0.75 dS m-1', 'N') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Slightly salty', 'saltContentValueCode-SL', 'http://w3id.org/glosis/model/codelists/saltContentValueCode-SL', 'Slightly salty soil with salt content 0.75–2 dS m-1', 'SL') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Strongly salty', 'saltContentValueCode-ST', 'http://w3id.org/glosis/model/codelists/saltContentValueCode-ST', 'Strongly salty soil with salt content 4–8 dS m-1', 'ST') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very strongly salty', 'saltContentValueCode-VST', 'http://w3id.org/glosis/model/codelists/saltContentValueCode-VST', 'Very strongly salty soil with salt content 8–15 dS m-1', 'VST') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Fresh or slightly weathered', 'weatheringValueCode-F', 'http://w3id.org/glosis/model/codelists/weatheringValueCode-F', 'Fragments show little or no signs of weathering.', 'F') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Strongly weathered', 'weatheringValueCode-S', 'http://w3id.org/glosis/model/codelists/weatheringValueCode-S', 'All but the most resistant minerals are weathered, strongly discoloured and altered throughout the fragments, which tend to disintegrate under only moderate pressure.', 'S') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Weathered', 'weatheringValueCode-W', 'http://w3id.org/glosis/model/codelists/weatheringValueCode-W', 'Partial weathering is indicated by discoloration and loss of crystal form in the outer parts of the fragments while the centres remain relatively fresh and the fragments have lost little of their original strength.', 'W') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Coarse', 'voidsDiameterValueCode-C', 'http://w3id.org/glosis/model/codelists/voidsDiameterValueCode-C', 'Coarse void with diameter between 5–20 m', 'C') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Fine', 'voidsDiameterValueCode-F', 'http://w3id.org/glosis/model/codelists/voidsDiameterValueCode-F', 'Fine void with diameter between 0.5–2 m', 'F') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('fine and very fine', 'voidsDiameterValueCode-FF', 'http://w3id.org/glosis/model/codelists/voidsDiameterValueCode-FF', 'Fine and very fine void with combination of fine and very fine type', 'FF') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('fine and medium', 'voidsDiameterValueCode-FM', 'http://w3id.org/glosis/model/codelists/voidsDiameterValueCode-FM', 'Fine and medium void with combination of fine and medium type', 'FM') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Medium', 'voidsDiameterValueCode-M', 'http://w3id.org/glosis/model/codelists/voidsDiameterValueCode-M', 'medium void with diameter 2–5', 'M') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('medium and coarse', 'voidsDiameterValueCode-MC', 'http://w3id.org/glosis/model/codelists/voidsDiameterValueCode-MC', 'Medium and coarse void with combination of medium and coarse type', 'MC') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very fine', 'voidsDiameterValueCode-V', 'http://w3id.org/glosis/model/codelists/voidsDiameterValueCode-V', 'Very fine void with diameter less than 0.5 m', 'V') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very coarse', 'voidsDiameterValueCode-VC', 'http://w3id.org/glosis/model/codelists/voidsDiameterValueCode-VC', 'very coarse void with diameter 20–50 m', 'VC') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Coarse sand', 'sandyTextureValueCode-CS', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-CS', 'Coarse sand is a subdivision of the unspecified Sand (S) textural class', 'CS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Coarse sandy loam', 'sandyTextureValueCode-CSL', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-CSL', 'Coarse sandy loam is a subdivision of the Sandy Loam (SL) textural class', 'CSL') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Fine sand', 'sandyTextureValueCode-FS', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-FS', 'Fine sand is a subdivision of the unspecified Sand (S) textural class', 'FS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Fine sandy loam', 'sandyTextureValueCode-FSL', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-FSL', 'Fine sandy loam is a subdivision of the Sandy Loam (SL) textural class', 'FSL') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Loamy coarse sand', 'sandyTextureValueCode-LCS', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-LCS', 'Loamy coarse sand is a subdivision of the Loamy sand (LS) textural class', 'LCS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Loamy fine sand', 'sandyTextureValueCode-LFS', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-LFS', 'Loamy fine sand is a subdivision of the Loamy sand (LS) textural class', 'LFS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Loamy very fine sand', 'sandyTextureValueCode-LVFS', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-LVFS', 'Loamy very fine sand is a subdivision of the Loamy sand (LS) textural class', 'LVFS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Medium sand', 'sandyTextureValueCode-MS', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-MS', 'Medium sand is a subdivision of the unspecified Sand (S) textural class', 'MS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Sand, unsorted', 'sandyTextureValueCode-US', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-US', 'Unsorted Sand is a subdivision of the unspecified Sand (S) textural class', 'US') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very fine sand', 'sandyTextureValueCode-VFS', 'http://w3id.org/glosis/model/codelists/sandyTextureValueCode-VFS', 'Very fine sand is a subdivision of the unspecified Sand (S) textural class', 'VFS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Non-sticky', 'stickinessValueCode-NST', 'http://w3id.org/glosis/model/codelists/stickinessValueCode-NST', 'After release of pressure, practically no soil material adheres to thumb and finger.', 'NST') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('slightly sticky to sticky', 'stickinessValueCode-SSS', 'http://w3id.org/glosis/model/codelists/stickinessValueCode-SSS', 'Additional code of combination of SST and ST', 'SSS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Slightly sticky', 'stickinessValueCode-SST', 'http://w3id.org/glosis/model/codelists/stickinessValueCode-SST', 'After pressure, soil material adheres to both thumb and finger but comes off one or the other rather cleanly. It is not appreciably stretched when the digits are separated.', 'SST') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Sticky', 'stickinessValueCode-ST', 'http://w3id.org/glosis/model/codelists/stickinessValueCode-ST', 'After pressure, soil material adheres to both thumb and finger and tends to stretch somewhat and pull apart rather than pulling free from either digit.', 'ST') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('sticky to very sticky', 'stickinessValueCode-SVS', 'http://w3id.org/glosis/model/codelists/stickinessValueCode-SVS', 'Additional code of combination of ST and VST', 'SVS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very sticky', 'stickinessValueCode-VST', 'http://w3id.org/glosis/model/codelists/stickinessValueCode-VST', 'After pressure, soil material adheres strongly to both thumb and finger and is decidedly stretched when they are separated.', 'VST') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Moderate', 'structureGradeValueCode-MO', 'http://w3id.org/glosis/model/codelists/structureGradeValueCode-MO', 'Aggregates are observable in place and there is a distinct arrangement of natural surfaces of weakness. When disturbed, the soil material breaks into a mixture of many entire aggregates, some broken aggregates, and little material without aggregates faces. Aggregates surfaces generally show distinct differences with the aggregates interiors.', 'MO') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Moderate to strong', 'structureGradeValueCode-MS', 'http://w3id.org/glosis/model/codelists/structureGradeValueCode-MS', 'Moderate to strong', 'MS') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Strong', 'structureGradeValueCode-ST', 'http://w3id.org/glosis/model/codelists/structureGradeValueCode-ST', 'Aggregates are clearly observable in place and there is a prominent arrangement of natural surfaces of weakness. When disturbed, the soil material separates mainly into entire aggregates. Aggregates surfaces generally differ markedly from aggregate interiors.', 'ST') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Weak', 'structureGradeValueCode-WE', 'http://w3id.org/glosis/model/codelists/structureGradeValueCode-WE', 'Aggregates are barely observable in place and there is only a weak arrangement of natural surfaces of weakness. When gently disturbed, the soil material breaks into a mixture of few entire aggregates, many broken aggregates, and much material without aggregate faces. Aggregate surfaces differ in some way from the aggregate interior.', 'WE') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Weak to moderate', 'structureGradeValueCode-WM', 'http://w3id.org/glosis/model/codelists/structureGradeValueCode-WM', 'Weak to moderate', 'WM') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Coarse/thick', 'structureSizeValueCode-CO', 'http://w3id.org/glosis/model/codelists/structureSizeValueCode-CO', '5–10 50–100 20–50', 'CO') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Extremely coarse', 'structureSizeValueCode-EC', 'http://w3id.org/glosis/model/codelists/structureSizeValueCode-EC', '– > 500 –', 'EC') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Fine/thin', 'structureSizeValueCode-FI', 'http://w3id.org/glosis/model/codelists/structureSizeValueCode-FI', '1–2 10–20 5–10', 'FI') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Medium', 'structureSizeValueCode-ME', 'http://w3id.org/glosis/model/codelists/structureSizeValueCode-ME', '2–5 20–50 10–20', 'ME') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very coarse/thick', 'structureSizeValueCode-VC', 'http://w3id.org/glosis/model/codelists/structureSizeValueCode-VC', '> 10 1.1.000 > 50', 'VC') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Very fine/thin', 'structureSizeValueCode-VF', 'http://w3id.org/glosis/model/codelists/structureSizeValueCode-VF', '< 1 < 10 < 5', 'VF') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Vesicular', 'voidsClassificationValueCode-B', 'http://w3id.org/glosis/model/codelists/voidsClassificationValueCode-B', 'Discontinuous spherical or elliptical voids (chambers) of sedimentary origin or formed by compressed air, e.g. gas bubbles in slaking crusts after heavy rainfall. Relatively unimportant in connection with plant growth.', 'B') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Channels', 'voidsClassificationValueCode-C', 'http://w3id.org/glosis/model/codelists/voidsClassificationValueCode-C', 'Elongated voids of faunal or floral origin, mostly tubular in shape and continuous, varying strongly in diameter. When wider than a few centimetres (burrow holes), they are more adequately described under biological activity.', 'C') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Interstitial', 'voidsClassificationValueCode-I', 'http://w3id.org/glosis/model/codelists/voidsClassificationValueCode-I', 'Controlled by the fabric, or arrangement, of the soil particles, also known as textural voids. Subdivision possible into simple packing voids, which relate to the packing of sand particles, and compound packing voids, which result from the packing of non-accommodating peds. Predominantly irregular in shape and interconnected, and hard to quantify in the field.', 'I') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Planes', 'voidsClassificationValueCode-P', 'http://w3id.org/glosis/model/codelists/voidsClassificationValueCode-P', 'Most planes are extra-pedal voids, related to accommodating ped surfaces or cracking patterns. They are often not persistent and vary in size, shape and quantity depending on the moisture condition of the soil. Planar voids may be recorded, describing width and frequency.', 'P') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.category_desc (category_name, category_desc_id, uri, definition, notation) VALUES ('Vughs', 'voidsClassificationValueCode-V', 'http://w3id.org/glosis/model/codelists/voidsClassificationValueCode-V', 'Mostly irregular, equidimensional voids of faunal origin or resulting from tillage or disturbance of other voids. Discontinuous or interconnected. May be quantified in specific cases.', 'V') ON CONFLICT DO NOTHING;
